search:nestjs+auth:nestjs jwt passport j.content:
- Install NestJS CLI globally using `npm install -g @nestjs/cli`
- Create a new NestJS project with `nest new project-name`
- Add Passport and JWT packages with `npm install --save @nestjs/passport passport passport-jwt`
- Configure JWT strategy in `auth.strategy.ts`:
  ```typescript
  import { Injectable } from '@nestjs/common';
  import { PassportStrategy } from '@nestjs/passport';
  import { ExtractJwt, Strategy } from 'passport-jwt';

  @Injectable()
  export class JwtStrategy extends PassportStrategy(Strategy) {
    constructor() {
      super({
        jwtFromRequest: ExtractJwt.fromAuthHeaderAsBearerToken(),
        ignoreExpiration: false,
        secretOrKey: 'your-secret-key',
      });
    }

    async validate(payload: any) {
      return { userId: payload.sub, username: payload.username };
    }
  }
  ```
- Configure Local strategy in `auth.strategy.ts`:
  ```typescript
  import { Injectable } from '@nestjs/common';
  import { PassportStrategy } from '@nestjs/passport';
  import { Strategy } from 'passport-local';

  @Injectable()
  export class LocalStrategy extends PassportStrategy(Strategy) {
    constructor() {
      super();
    }

    async validate(username: string, password: string): Promise<any> {
      // Implement your user validation logic here
      return { username };
    }
  }
  ```
- Update `auth.module.ts` to import and use the strategies:
  ```typescript
  import { Module } from '@nestjs/common';
  import { AuthService } from './auth.service';
  import { JwtStrategy } from './jwt.strategy';
  import { LocalStrategy } from './local.strategy';

  @Module({
    imports: [],
    controllers: [],
    providers: [AuthService, JwtStrategy, LocalStrategy],
  })
  export class AuthModule {}
  ```
- Use `@UseGuards(AuthGuard('jwt'))` or `@UseGuards(AuthGuard('local'))` to protect routes.
